const items = $input.all();
const seen = new Set();
const cleaned = [];

for (const item of items) {
  const text = item.json.translated_text || '';
  const cleanText = text.trim().toLowerCase();

  // Skip empty or duplicate messages
  if (!cleanText || seen.has(cleanText)) continue;

  seen.add(cleanText);
  cleaned.push({
    json: {
      ticket_id: item.json.ticket_id,
      clean_text: cleanText,
      sentiment: item.json.sentiment || 0,
      churn_risk: item.json.churn_risk || 0,
      account_tier: item.json.account_tier || 'free',
      original_language: item.json.original_language,
      original_message: item.json.original_message
    }
  });
}

return cleaned;

const items = $input.all();
const threshold = $('Workflow Configuration').first().json.similarityThreshold;
const OPENAI_API_KEY = '<__PLACEHOLDER_VALUE__OpenAI API Key__>';

// Function to generate embeddings via OpenAI API
async function getEmbedding(text) {
  const response = await fetch('https://api.openai.com/v1/embeddings', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${OPENAI_API_KEY}`
    },
    body: JSON.stringify({
      model: 'text-embedding-3-small',
      input: text
    })
  });
  const data = await response.json();
  return data.data[0].embedding;
}

// Generate embeddings for each ticket
const ticketsWithEmbeddings = await Promise.all(
  items.map(async (item) => ({
    ...item.json,
    embedding: await getEmbedding(item.json.clean_text)
  }))
);

// Cosine similarity function
function cosineSimilarity(a, b) {
  const dotProduct = a.reduce((sum, val, i) => sum + val * b[i], 0);
  const magA = Math.sqrt(a.reduce((sum, val) => sum + val * val, 0));
  const magB = Math.sqrt(b.reduce((sum, val) => sum + val * val, 0));
  return dotProduct / (magA * magB);
}

// Cluster tickets by similarity
const clusters = [];
const assigned = new Set();

for (let i = 0; i < ticketsWithEmbeddings.length; i++) {
  if (assigned.has(i)) continue;

  const cluster = {
    cluster_id: `cluster_${clusters.length + 1}`,
    tickets: [ticketsWithEmbeddings[i]]
  };
  assigned.add(i);

  for (let j = i + 1; j < ticketsWithEmbeddings.length; j++) {
    if (assigned.has(j)) continue;

    const similarity = cosineSimilarity(
      ticketsWithEmbeddings[i].embedding,
      ticketsWithEmbeddings[j].embedding
    );

    if (similarity >= threshold) {
      cluster.tickets.push(ticketsWithEmbeddings[j]);
      assigned.add(j);
    }
  }

  clusters.push(cluster);
}

// Return each ticket with its cluster assignment
return clusters.flatMap(cluster => 
  cluster.tickets.map(ticket => ({
    json: {
      ticket_id: ticket.ticket_id,
      clean_text: ticket.clean_text,
      sentiment: ticket.sentiment,
      churn_risk: ticket.churn_risk,
      account_tier: ticket.account_tier,
      original_language: ticket.original_language,
      original_message: ticket.original_message,
      cluster_id: cluster.cluster_id,
      cluster_size: cluster.tickets.length
    }
  }))
);

const items = $input.all();
const config = $('Workflow Configuration').first().json;

const scoredClusters = items.map(item => {
  const cluster = item.json;
  const tickets = cluster.aggregatedData || [];

  // Calculate metrics
  const ticketCount = tickets.length;
  const avgSentiment = tickets.reduce((sum, t) => sum + (t.sentiment || 0), 0) / ticketCount;
  const avgChurnRisk = tickets.reduce((sum, t) => sum + (t.churn_risk || 0), 0) / ticketCount;
  const enterpriseCount = tickets.filter(t => t.account_tier === 'enterprise').length;
  const enterpriseRatio = enterpriseCount / ticketCount;

  // Weighted severity score
  const severityScore = 
    (config.frequencyWeight * Math.log(ticketCount + 1)) +
    (config.sentimentWeight * Math.abs(avgSentiment)) +
    (config.churnWeight * avgChurnRisk) +
    (config.tierWeight * enterpriseRatio);

  return {
    json: {
      ...cluster,
      metrics: {
        ticket_count: ticketCount,
        avg_sentiment: avgSentiment,
        avg_churn_risk: avgChurnRisk,
        enterprise_ratio: enterpriseRatio,
        severity_score: severityScore
      }
    }
  };
});

// Sort by severity score descending
return scoredClusters.sort((a, b) => 
  b.json.metrics.severity_score - a.json.metrics.severity_score
);

